    /**
     * Resuelve el id de categoría a partir del nombre.
     * Si no existe, lanza una excepción para que lo notes antes de ejecutar en producción.
     */
    private function catId(array &$cache, string $nombre): int
    {
        $nombre = trim($nombre);
        if (!isset($cache[$nombre])) {
            $id = DB::table('categorias_insumos')
                ->whereRaw('TRIM(nombre) = ?', [$nombre])
                ->value('id');

            if (!$id) {
                throw new \RuntimeException("Categoría no encontrada: \"{$nombre}\". Creala en categorias_insumos antes de correr el seeder.");
            }
            $cache[$nombre] = $id;
        }
        return $cache[$nombre];
    }

    /** Convierte stock vacío / "-" a 0 */
    private function stock(mixed $v): int
    {
        if ($v === null || $v === '' || $v === '-') return 0;
        return (int) $v;
    }

