            [793, 'Correa de transmisión',                            'Motosierras',          'UNIDAD', 0,  0,   16],
            [794, 'Protectores auditivos',                            'Motosierras',          'UNIDAD', 0,  0,   16],
            [795, 'Protector ocular negros (anteojos)',               'Motosierras',          'UNIDAD', 0,  0,   16],
            [796, 'Accesorios',                                       'Motosierras',          'UNIDAD', 0,  0,   16],
            [797, 'Correa de caja',                                   'Motosierras',          'UNIDAD', 0,  0,   16],
            [798, 'Protector ocular transparente (anteojos)',         'Motosierras',          'UNIDAD', 0,  0,   16],
            [799, 'Rodamientos 6203',                                 'Motosierras',          'UNIDAD', 0,  0,   16],
            [800, 'Rodamientos 6204',                                 'Motosierras',          'UNIDAD', 0,  0,   16],
            [801, 'Piston',                                           'Motosierras',          'UNIDAD', 0,  0,   16],
        ];

        // Insertar en lotes de 50 para no saturar la memoria
        foreach (array_chunk($rows, 50) as $chunk) {
            $insert = [];
            foreach ($chunk as [$id, $insumo, $catNombre, $unidad, $stock_actual, $stock_minimo, $id_deposito]) {
                $insert[] = [
                    'id'           => $id,
                    'insumo'       => $insumo,
                    'id_categoria' => $this->catId($catCache, $catNombre),
                    'unidad'       => $unidad,
                    'stock_actual' => $stock_actual,
                    'stock_minimo' => $stock_minimo,
                    'id_deposito'  => $id_deposito,
                    'created_at'   => $now,
                    'updated_at'   => $now,
                ];
            }
            DB::table('insumos')->insert($insert);
        }

        // Reajustar el auto_increment al valor más alto + 1
        DB::statement('ALTER TABLE insumos AUTO_INCREMENT = 802;');

        $this->command->info('✅ Tabla insumos poblada con ' . count($rows) . ' registros.');
    }
}